def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.zeros_like(bins)
    for i in range(len(bins)):
        capacity = bins[i]
        if capacity <= 0:
            priorities[i] = np.inf
            continue
        ratio = item / capacity
        if ratio > 1:
            priorities[i] = 1000 + (ratio - 1) * 500
        else:
            log_ratio = np.log(ratio + 1e-9)
            priority = -log_ratio * 10
            if capacity < item * 1.5:
                priority *= 1.5
            else:
                priority /= 2
            priorities[i] = priority
        if i % 2 == 0:
            priorities[i] += i * 0.1
        else:
            priorities[i] -= i * 0.1
    min_priority = np.min(priorities[np.isfinite(priorities)])
    for i in range(len(priorities)):
        if priorities[i] == np.inf:
            priorities[i] = min_priority + 100
    return priorities
